import React, { useState, useEffect } from 'react';
import Logo from './Logo.png'; 

// BRAND COLORS
const gold = '#D4AF37'; 
const terracotta = '#C04000'; 
const softCream = '#FDF5E6'; 

function App() {
  const [activeCategory, setActiveCategory] = useState('Small Chops');
  const [currentSlide, setCurrentSlide] = useState(0);
  const [cart, setCart] = useState([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [showBankDetails, setShowBankDetails] = useState(false);
  const [isClockedIn, setIsClockedIn] = useState(false);

  const whatsappNumber = "2349122731172";
  const bankInfo = { 
    bank: "PREMIUMTRUST BANK", 
    account: "0112326977", 
    name: "OLUKOYA OMOTOYOSI" 
  };

  const slides = [
    { title: "EVERY BITE WORTH IT!", subtitle: "Lagos' finest grills & chops.", bgImage: "/images/chops_bg.jpg" },
    { title: "MADE FOR REAL CRAVINGS", subtitle: "Don't overthink it... just eat!", bgImage: "/images/wigs_bg.jpg" },
    { title: "PREMIUM TASTE, 9JA FLAVOR", subtitle: "The perfect balance of comfort.", bgImage: "/images/lunch_bg.jpg" }
  ];

  const menuData = {
    CHOPS: [
      { id: 1, name: "The Starter Pack", price: "15,000", desc: "7 Samosas, 7 Springrolls, 15 Puff-puff, 10 Mosa, 4 Grilled Chicken.", img: "/images/starter.jpg" },
      { id: 2, name: "The Signature Platter", price: "25,000", desc: "10 Samosas, 10 Springrolls, 25 Puff-puff, 20 Mosa, 8 Grilled Chicken.", img: "/images/signature.jpg" },
      { id: 3, name: "The Owambe Special", price: "150,000", desc: "Full event catering for 50 people.", img: "/images/owambe.jpg" },
      { id: 4, name: "The Customized Package", price: "200,000", desc: "Bespoke menu for 60 people and above.", img: "/images/custom.jpg", isCustom: true }
    ],
    LUNCH: [
      { day: "Monday", meal: "Smoky Jollof, Grilled Chicken & Salad" },
      { day: "Tuesday", meal: "Creamy Pasta, Sauteed Prawns & Garlic Bread" },
      { day: "Wednesday", meal: "Native Rice, Shredded Beef & Fried Plantain" },
      { day: "Thursday", meal: "Stir-fry Noodles, Teriyaki Wings & Veggies" },
      { day: "Friday", meal: "Chef's Special Surprise (TGIF Menu)" }
    ],
    WIGS: [
      { type: "Human Hair", items: [
          { id: 201, name: "Raw Cambodian", price: "85,000", desc: "14\" Frontal Unit", img: "/images/hair1.jpg" },
          { id: 202, name: "Bone Straight", price: "120,000", desc: "12\" Double Drawn", img: "/images/hair2.jpg" }
      ]},
      { type: "Premium Fibre", items: [
          { id: 203, name: "Sleek Straight", price: "35,000", desc: "Heat Resistant", img: "/images/hair3.jpg" },
          { id: 204, name: "Deep Wave", price: "38,000", desc: "Pre-styled", img: "/images/hair4.jpg" }
      ]},
      { type: "Hair Blend", items: [
          { id: 205, name: "Piano Wavy", price: "25,000", desc: "24\" T-Closure", img: "/images/hair5.jpg" }
      ]}
    ]
  };

  useEffect(() => {
    const timer = setInterval(() => setCurrentSlide((s) => (s + 1) % slides.length), 5000);
    return () => clearInterval(timer);
  }, [slides.length]);

  const addToCart = (item) => setCart([...cart, item]);
  const total = cart.reduce((acc, item) => acc + parseInt(item.price.replace(/,/g, '')), 0);

  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', color: '#fff', fontFamily: 'system-ui, sans-serif' }}>
      
      {/* 1. STICKY HEADER */}
      <header style={{ padding: '15px 20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', backgroundColor: '#000', position: 'sticky', top: 0, zIndex: 1000, borderBottom: '1px solid #1a1a1a' }}>
        <img src={Logo} alt="Logo" style={{ height: '50px' }} />
        <div onClick={() => setIsCartOpen(true)} style={{ backgroundColor: terracotta, color: '#fff', padding: '8px 18px', borderRadius: '20px', display: 'flex', alignItems: 'center', gap: '8px', cursor: 'pointer', fontWeight: 'bold', fontSize: '0.9rem' }}>
          🛒 {cart.length}
        </div>
      </header>

      {/* 2. CORRECTED PICTURE-IN-FRAME SLIDER */}
      <div style={{ padding: '10px 0', overflow: 'hidden' }}>
        <div style={{ height: '240px', position: 'relative', backgroundColor: terracotta, borderRadius: '25px', margin: '0 15px', overflow: 'hidden', boxShadow: 'inset 0 0 50px rgba(0,0,0,0.2)' }}>
          {slides.map((slide, index) => (
            <div key={index} style={{ 
              position: 'absolute', width: '100%', height: '100%', 
              display: 'flex', alignItems: 'center', 
              opacity: index === currentSlide ? 1 : 0, 
              transition: 'opacity 0.8s ease-in-out',
              padding: '0 20px'
            }}>
              {/* TEXT SIDE */}
              <div style={{ flex: 1.2, color: '#fff', zIndex: 2, paddingRight: '10px' }}>
                <h2 style={{ fontSize: '1.4rem', fontWeight: '900', margin: 0, lineHeight: 1.1, textShadow: '0 2px 4px rgba(0,0,0,0.3)' }}>{slide.title}</h2>
                <p style={{ fontSize: '0.8rem', margin: '10px 0 0', color: softCream, fontWeight: '500' }}>{slide.subtitle}</p>
              </div>
              
              {/* IMAGE FRAME - NOW WITH CONTAIN FIT FOR FULL VISIBILITY */}
              <div style={{ flex: 1, height: '160px', borderRadius: '15px', backgroundColor: '#000', overflow: 'hidden', border: '2px solid rgba(255,255,255,0.1)', boxShadow: '0 15px 30px rgba(0,0,0,0.4)' }}>
                <img 
                  src={process.env.PUBLIC_URL + slide.bgImage} 
                  style={{ width: '100%', height: '100%', objectFit: 'contain' }} // ENTIRE PHOTO IS VISIBLE NOW
                  alt={slide.title} 
                />
              </div>
            </div>
          ))}
          
          {/* DOT INDICATORS */}
          <div style={{ position: 'absolute', bottom: '15px', left: '20px', display: 'flex', gap: '6px' }}>
            {slides.map((_, i) => (
              <div key={i} style={{ width: i === currentSlide ? '20px' : '6px', height: '6px', borderRadius: '10px', backgroundColor: '#fff', transition: 'width 0.3s' }}></div>
            ))}
          </div>
        </div>
      </div>

      {/* 3. NAVIGATION CATEGORIES */}
      <div style={{ display: 'flex', gap: '10px', overflowX: 'auto', padding: '15px 20px', scrollbarWidth: 'none' }}>
        {['Small Chops', 'Office Lunch', 'Wigs'].map((item) => (
          <button key={item} onClick={() => setActiveCategory(item)} style={{ whiteSpace: 'nowrap', padding: '10px 22px', borderRadius: '25px', border: 'none', backgroundColor: activeCategory === item ? terracotta : '#111', color: '#fff', fontWeight: '800', fontSize: '0.9rem' }}>
            {item}
          </button>
        ))}
      </div>

      {/* 4. RESTORED STORE CONTENT */}
      <main style={{ paddingBottom: '140px' }}>
        {activeCategory === 'Small Chops' && menuData.CHOPS.map((item) => (
          <div key={item.id} style={{ display: 'flex', backgroundColor: '#0A0A0A', borderRadius: '20px', margin: '0 20px 15px', padding: '15px', alignItems: 'center', border: '1px solid #1a1a1a' }}>
            <div style={{ width: '90px', height: '90px', borderRadius: '15px', overflow: 'hidden', flexShrink: 0 }}>
              <img src={item.img} style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt="" />
            </div>
            <div style={{ flex: 1, paddingLeft: '15px' }}>
              <h4 style={{ fontSize: '1rem', margin: 0, fontWeight: '700' }}>{item.name}</h4>
              <div style={{ color: gold, fontWeight: 'bold', marginTop: '5px' }}>₦{item.price}</div>
            </div>
            {item.isCustom ? (
              <button onClick={() => window.open(`https://wa.me/${whatsappNumber}?text=Book ${item.name}`)} style={{ backgroundColor: gold, padding: '10px 18px', borderRadius: '20px', border: 'none', fontWeight: '900', fontSize: '0.75rem' }}>BOOK</button>
            ) : (
              <button onClick={() => addToCart(item)} style={{ backgroundColor: terracotta, padding: '10px 18px', borderRadius: '20px', border: 'none', color: '#fff', fontWeight: '900', fontSize: '0.75rem' }}>+ ADD</button>
            )}
          </div>
        ))}

        {activeCategory === 'Office Lunch' && (
          <div style={{ padding: '0 20px' }}>
            <div style={{ backgroundColor: '#111', padding: '30px', borderRadius: '20px', textAlign: 'center', marginBottom: '20px', border: `1px solid ${isClockedIn ? '#2ecc71' : terracotta}` }}>
              <h4 style={{ color: gold, marginBottom: '10px' }}>{isClockedIn ? "Order Logged! ✅" : "Daily Office Fuel 🍲"}</h4>
              <button onClick={() => setIsClockedIn(true)} style={{ backgroundColor: isClockedIn ? '#2ecc71' : terracotta, color: '#fff', border: 'none', padding: '14px 30px', borderRadius: '15px', fontWeight: '900' }}>{isClockedIn ? "LOGGED IN" : "CLOCK IN"}</button>
            </div>
            {menuData.LUNCH.map((item) => (
              <div key={item.day} style={{ padding: '15px 0', borderBottom: '1px solid #1a1a1a', display: 'flex', justifyContent: 'space-between' }}>
                <span style={{ color: terracotta, fontWeight: '800' }}>{item.day}</span>
                <span style={{ textAlign: 'right', flex: 1, marginLeft: '20px', color: '#ccc' }}>{item.meal}</span>
              </div>
            ))}
          </div>
        )}

        {activeCategory === 'Wigs' && menuData.WIGS.map((cat) => (
          <div key={cat.type} style={{ padding: '0 20px', marginBottom: '25px' }}>
            <h3 style={{ fontSize: '0.85rem', color: terracotta, textTransform: 'uppercase', marginBottom: '15px', letterSpacing: '1px' }}>{cat.type}</h3>
            {cat.items.map((item) => (
              <div key={item.id} style={{ display: 'flex', backgroundColor: '#0A0A0A', borderRadius: '18px', padding: '15px', alignItems: 'center', border: '1px solid #1a1a1a', marginBottom: '12px' }}>
                <div style={{ width: '85px', height: '85px', borderRadius: '12px', overflow: 'hidden', flexShrink: 0 }}>
                  <img src={item.img} style={{ width: '100%', height: '100%', objectFit: 'cover' }} alt="" />
                </div>
                <div style={{ flex: 1, paddingLeft: '15px' }}>
                  <h4 style={{ fontSize: '1rem', margin: 0 }}>{item.name}</h4>
                  <div style={{ color: gold, fontWeight: 'bold', marginTop: '5px' }}>₦{item.price}</div>
                </div>
                <button onClick={() => addToCart(item)} style={{ backgroundColor: terracotta, padding: '10px 18px', borderRadius: '20px', border: 'none', color: '#fff', fontWeight: '900', fontSize: '0.75rem' }}>ADD</button>
              </div>
            ))}
          </div>
        ))}
      </main>

      {/* 5. FLOATING BOTTOM CART */}
      {cart.length > 0 && (
        <div onClick={() => setIsCartOpen(true)} style={{ position: 'fixed', bottom: '25px', left: '50%', transform: 'translateX(-50%)', width: '90%', backgroundColor: terracotta, padding: '18px 25px', borderRadius: '25px', display: 'flex', justifyContent: 'space-between', zIndex: 1001, boxShadow: '0 10px 30px rgba(0,0,0,0.6)', cursor: 'pointer' }}>
          <span style={{ fontWeight: '900' }}>{cart.length} ITEMS</span>
          <span style={{ fontWeight: '900' }}>CHECKOUT BOX ₦{total.toLocaleString()}</span>
        </div>
      )}
    </div>
  );
}

export default App;
